#define fp double

#define NUMBER_PAR_PER_BOX 100

#ifndef NUMBER_THREADS
#define NUMBER_THREADS 128
#endif

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
    fp x, y, z;
} THREE_VECTOR;

typedef struct
{
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str
{
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str
{
    fp alpha;
} par_str;

typedef struct dim_str
{
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

kernel void kernel_gpu_opencl(
    par_str d_par_gpu,
    dim_str d_dim_gpu,
    const box_str* d_box_gpu,
    const FOUR_VECTOR* d_rv_gpu,
    const fp* d_qv_gpu,
    FOUR_VECTOR* d_fv_gpu)
{
    int bx = get_global_id(0) / NUMBER_THREADS;
    int tx = get_local_id(0);
    int wtx = tx;

    if(bx < d_dim_gpu.number_boxes){
        fp a2 = 2.0*d_par_gpu.alpha*d_par_gpu.alpha;

        int first_i;
        const FOUR_VECTOR* rA;
        FOUR_VECTOR* fA;
        FOUR_VECTOR rA_shared[100];

        int pointer;
        int k = 0;
        int first_j;
        const FOUR_VECTOR* rB;
        const fp* qB;
        int j = 0;
        FOUR_VECTOR rB_shared[100];
        fp qB_shared[100];

        fp r2;
        fp u2;
        fp vij;
        fp fs;
        fp fxij;
        fp fyij;
        fp fzij;
        THREE_VECTOR d;

        first_i = d_box_gpu[bx].offset;
        rA = &d_rv_gpu[first_i];
        fA = &d_fv_gpu[first_i];

        while(wtx < NUMBER_PAR_PER_BOX){
            rA_shared[wtx] = rA[wtx];
            wtx = wtx + NUMBER_THREADS;
        }
        wtx = tx;
        barrier(CLK_LOCAL_MEM_FENCE);

        for (k=0; k<(1+d_box_gpu[bx].nn); k++){
            if(k==0){
                pointer = bx;
            }
            else{
                pointer = d_box_gpu[bx].nei[k-1].number;
            }

            first_j = d_box_gpu[pointer].offset;
            rB = &d_rv_gpu[first_j];
            qB = &d_qv_gpu[first_j];

            while(wtx < NUMBER_PAR_PER_BOX){
                rB_shared[wtx] = rB[wtx];
                qB_shared[wtx] = qB[wtx];
                wtx = wtx + NUMBER_THREADS;
            }
            wtx = tx;
            barrier(CLK_LOCAL_MEM_FENCE);

            while(wtx < NUMBER_PAR_PER_BOX){
                for (j=0; j<NUMBER_PAR_PER_BOX; j++){
                    THREE_VECTOR vecA = {rA_shared[wtx].x, rA_shared[wtx].y, rA_shared[wtx].z};
                    THREE_VECTOR vecB = {rB_shared[j].x, rB_shared[j].y, rB_shared[j].z};
                    r2 = (fp)rA_shared[wtx].v + (fp)rB_shared[j].v - DOT(vecA, vecB);
                    u2 = a2*r2;
                    vij= exp(-u2);
                    fs = 2*vij;

                    d.x = (fp)rA_shared[wtx].x  - (fp)rB_shared[j].x;
                    fxij=fs*d.x;
                    d.y = (fp)rA_shared[wtx].y  - (fp)rB_shared[j].y;
                    fyij=fs*d.y;
                    d.z = (fp)rA_shared[wtx].z  - (fp)rB_shared[j].z;
                    fzij=fs*d.z;

                    fA[wtx].v +=  (double)((fp)qB_shared[j]*vij);
                    fA[wtx].x +=  (double)((fp)qB_shared[j]*fxij);
                    fA[wtx].y +=  (double)((fp)qB_shared[j]*fyij);
                    fA[wtx].z +=  (double)((fp)qB_shared[j]*fzij);
                }
                wtx = wtx + NUMBER_THREADS;
            }
            wtx = tx;
            barrier(CLK_LOCAL_MEM_FENCE);
        }
    }
}
